toff_t TIFFWritePrivateDataSubDirectory(
    TIFF *tif, uint32_t pdir_fieldsset[], int pdir_fields_last,
    TIFFFieldInfo *field_info, int (*getFieldFn)(TIFF *tif, ttag_t tag, ...))
{
    uint16_t dircount;
    uint32_t diroff, nextdiroff;
    ttag_t tag;
    uint32_t nfields;
    tsize_t dirsize;
    char *data;
    TIFFDirEntry *dir;
    u_long b, *fields, fields_size;
    toff_t directory_offset;
    TIFFFieldInfo *fip;

    /*
     * Deleted out all of the encoder flushing and such code from here -
     * not necessary for subdirectories.
     */

    /* Finish writing out any image data. */
    TIFFFlushData(tif);

    /*
     * Size the directory so that we can calculate
     * offsets for the data items that aren't kept
     * in-place in each field.
     */
    nfields = 0;
    for (b = 0; b <= pdir_fields_last; b++)
        if (FieldSet(pdir_fieldsset, b))
            /* Deleted code to make size of first 4 tags 2
               instead of 1. */
            nfields += 1;
    dirsize = nfields * sizeof(TIFFDirEntry);
    data = (char *)_TIFFmalloc(dirsize);
    if (data == NULL)
    {
        TIFFErrorExtR(tif, tif->tif_name,
                      "Cannot write private subdirectory, out of space");
        return (0);
    }
    /*
     * Place directory in data section of the file. If there isn't one
     * yet, place it at the end of the file. The directory is treated as
     * data, so we don't link it into the directory structure at all.
     */
    if (tif->tif_dataoff == 0)
        tif->tif_dataoff = (TIFFSeekFile(tif, (toff_t)0, SEEK_END) + 1) & ~1;
    diroff = tif->tif_dataoff;
    tif->tif_dataoff =
        (toff_t)(diroff + sizeof(uint16_t) + dirsize + sizeof(toff_t));
    if (tif->tif_dataoff & 1)
        tif->tif_dataoff++;
    (void)TIFFSeekFile(tif, tif->tif_dataoff, SEEK_SET);
    /*tif->tif_curdir++;*/
    dir = (TIFFDirEntry *)data;
    /*
     * Setup external form of directory
     * entries and write data items.
     */
    /*
     * We make a local copy of the fieldsset here so that we don't mess
     * up the original one when we call ResetFieldBit(). But I'm not sure
     * why the original code calls ResetFieldBit(), since we're already
     * going through the fields in order...
     *
     * fields_size is the number of uint32_t's we will need to hold the
     * bit-mask for all of the fields. If our highest field number is
     * 100, then we'll need 100 / (8*4)+1 == 4 uint32_t's to hold the
     * fieldset.
     *
     * Unlike the original code, we allocate fields dynamically based
     * on the requested pdir_fields_last value, allowing private
     * data subdirectories to contain more than the built-in code's limit
     * of 95 tags in a directory.
     */
    fields_size = pdir_fields_last / (8 * sizeof(uint32_t)) + 1;
    fields = _TIFFmalloc(fields_size * sizeof(uint32_t));
    _TIFFmemcpy(fields, pdir_fieldsset, fields_size * sizeof(uint32_t));

    /* Deleted "write out extra samples tag" code here. */

    /* Deleted code for checking a billion little special cases for the
     * standard TIFF tags. Should add a general mechanism for overloading
     * write function for each field, just like Brian kept telling me!!!
     */
    for (fip = field_info; fip->field_tag; fip++)
    {
        /* Deleted code to check for FIELD_IGNORE!! */
        if (/* fip->field_bit == FIELD_IGNORE || */
            !FieldSet(fields, fip->field_bit))
            continue;
        if (!TIFFWriteNormalSubTag(tif, dir, fip, getFieldFn))
            goto bad;
        dir++;
        ResetFieldBit(fields, fip->field_bit);
    }

    /* Now we've written all of the referenced data, and are about to
       write the main directory structure, so grab the tif_dataoff value
       now so we can remember where we wrote the directory. */
    directory_offset = tif->tif_dataoff;

    /*
     * Write directory.
     */
    dircount = (uint16_t)nfields;
    /* Deleted code to link to the next directory - we set it to zero! */
    nextdiroff = 0;
    if (tif->tif_flags & TIFF_SWAB)
    {
        /*
         * The file's byte order is opposite to the
         * native machine architecture.  We overwrite
         * the directory information with impunity
         * because it'll be released below after we
         * write it to the file.  Note that all the
         * other tag construction routines assume that
         * we do this byte-swapping; i.e. they only
         * byte-swap indirect data.
         */
        for (dir = (TIFFDirEntry *)data; dircount; dir++, dircount--)
        {
            TIFFSwabArrayOfShort(&dir->tdir_tag, 2);
            TIFFSwabArrayOfLong(&dir->tdir_count, 2);
        }
        dircount = (uint16_t)nfields;
        TIFFSwabShort(&dircount);
        TIFFSwabLong(&nextdiroff);
    }

    (void)TIFFSeekFile(tif, tif->tif_dataoff, SEEK_SET);
    if (!WriteOK(tif, &dircount, sizeof(dircount)))
    {
        TIFFErrorExtR(tif, tif->tif_name,
                      "Error writing private subdirectory count");
        goto bad;
    }
    if (!WriteOK(tif, data, dirsize))
    {
        TIFFErrorExtR(tif, tif->tif_name,
                      "Error writing private subdirectory contents");
        goto bad;
    }
    if (!WriteOK(tif, &nextdiroff, sizeof(nextdiroff)))
    {
        TIFFErrorExtR(tif, tif->tif_name,
                      "Error writing private subdirectory link");
        goto bad;
    }
    tif->tif_dataoff += sizeof(dircount) + dirsize + sizeof(nextdiroff);

    _TIFFfree(data);
    _TIFFfree(fields);
    tif->tif_flags &= ~TIFF_DIRTYDIRECT;

#if (0)
    /* This stuff commented out because I don't think we want it for
       subdirectories, but I could be wrong. */
    (*tif->tif_cleanup)(tif);

    /*
     * Reset directory-related state for subsequent
     * directories.
     */
    TIFFDefaultDirectory(tif);
    tif->tif_curoff = 0;
    tif->tif_row = (uint32_t)-1;
    tif->tif_curstrip = (tstrip_t)-1;
#endif

    return (directory_offset);
bad:
    _TIFFfree(data);
    _TIFFfree(fields);
    return (0);
}

static int TIFFWriteNormalSubTag(TIFF *tif, TIFFDirEntry *dir,
                                 const TIFFFieldInfo *fip,
                                 int (*getFieldFn)(TIFF *tif, ttag_t tag, ...))
{
    u_short wc = (u_short)fip->field_writecount;

    dir->tdir_tag = fip->field_tag;
    dir->tdir_type = (u_short)fip->field_type;
    dir->tdir_count = wc;
#define WRITEF(x, y) x(tif, fip->field_type, fip->field_tag, dir, wc, y)
    switch (fip->field_type)
    {
        case TIFF_SHORT:
        case TIFF_SSHORT:
            if (wc > 1)
            {
                uint16_t *wp;
                if (wc == (u_short)TIFF_VARIABLE)
                {
                    (*getFieldFn)(tif, fip->field_tag, &wc, &wp);
                    dir->tdir_count = wc;
                }
                else
                    (*getFieldFn)(tif, fip->field_tag, &wp);
                if (!WRITEF(TIFFWriteShortArray, wp))
                    return (0);
            }
            else
            {
                uint16_t sv;
                (*getFieldFn)(tif, fip->field_tag, &sv);
                dir->tdir_offset = TIFFInsertData(tif, dir->tdir_type, sv);
            }
            break;
        case TIFF_LONG:
        case TIFF_SLONG:
            if (wc > 1)
            {
                uint32_t *lp;
                if (wc == (u_short)TIFF_VARIABLE)
                {
                    (*getFieldFn)(tif, fip->field_tag, &wc, &lp);
                    dir->tdir_count = wc;
                }
                else
                    (*getFieldFn)(tif, fip->field_tag, &lp);
                if (!WRITEF(TIFFWriteLongArray, lp))
                    return (0);
            }
            else
            {
                /* XXX handle LONG->SHORT conversion */
                (*getFieldFn)(tif, fip->field_tag, &dir->tdir_offset);
            }
            break;
        case TIFF_RATIONAL:
        case TIFF_SRATIONAL:
            if (wc > 1)
            {
                float *fp;
                if (wc == (u_short)TIFF_VARIABLE)
                {
                    (*getFieldFn)(tif, fip->field_tag, &wc, &fp);
                    dir->tdir_count = wc;
                }
                else
                    (*getFieldFn)(tif, fip->field_tag, &fp);
                if (!WRITEF(TIFFWriteRationalArray, fp))
                    return (0);
            }
            else
            {
                float fv;
                (*getFieldFn)(tif, fip->field_tag, &fv);
                if (!WRITEF(TIFFWriteRationalArray, &fv))
                    return (0);
            }
            break;
        case TIFF_FLOAT:
            if (wc > 1)
            {
                float *fp;
                if (wc == (u_short)TIFF_VARIABLE)
                {
                    (*getFieldFn)(tif, fip->field_tag, &wc, &fp);
                    dir->tdir_count = wc;
                }
                else
                    (*getFieldFn)(tif, fip->field_tag, &fp);
                if (!WRITEF(TIFFWriteFloatArray, fp))
                    return (0);
            }
            else
            {
                float fv;
                (*getFieldFn)(tif, fip->field_tag, &fv);
                if (!WRITEF(TIFFWriteFloatArray, &fv))
                    return (0);
            }
            break;
        case TIFF_DOUBLE:
            /* Hey - I think this is a bug, or at least a "gross
               inconsistency", in the TIFF library. Look at the original
               TIFF library code below within the "#if (0) ... #else".
               Just from the type of *dp, you can see that this code
               expects TIFFGetField() to be handed a double ** for
               any TIFF_DOUBLE tag, even for the constant wc==1 case.
               This is totally inconsistent with other fields (like
               TIFF_FLOAT, above) and is also inconsistent with the
               TIFFSetField() function for TIFF_DOUBLEs, which expects
               to be passed a single double by value for the wc==1 case.
               (See the handling of TIFFFetchNormalTag() in tif_dirread.c
               for an example.) Maybe this function was written before
               TIFFWriteDoubleArray() was written, not that that's an
               excuse. Anyway, the new code below is a trivial modification
               of the TIFF_FLOAT code above. The fact that even single
               doubles get written out in the data segment and get an
               offset value stored is irrelevant here - that is all
               handled by TIFFWriteDoubleArray(). */
#if (0)
        {
            double *dp;
            if (wc == (u_short)TIFF_VARIABLE)
            {
                (*getFieldFn)(tif, fip->field_tag, &wc, &dp);
                dir->tdir_count = wc;
            }
            else
                (*getFieldFn)(tif, fip->field_tag, &dp);
            TIFFCvtNativeToIEEEDouble(tif, wc, dp);
            if (!TIFFWriteData(tif, dir, (char *)dp))
                return (0);
        }
#else
            if (wc > 1)
            {
                double *dp;
                if (wc == (u_short)TIFF_VARIABLE)
                {
                    (*getFieldFn)(tif, fip->field_tag, &wc, &dp);
                    dir->tdir_count = wc;
                }
                else
                    (*getFieldFn)(tif, fip->field_tag, &dp);
                if (!WRITEF(TIFFWriteDoubleArray, dp))
                    return (0);
            }
            else
            {
                double dv;
                (*getFieldFn)(tif, fip->field_tag, &dv);
                if (!WRITEF(TIFFWriteDoubleArray, &dv))
                    return (0);
            }
#endif
        break;
        case TIFF_ASCII:
        {
            char *cp;
            (*getFieldFn)(tif, fip->field_tag, &cp);
            dir->tdir_count = (uint32_t)(strlen(cp) + 1);
            if (!TIFFWriteByteArray(tif, dir, cp))
                return (0);
        }
        break;
        case TIFF_UNDEFINED:
        {
            char *cp;
            if (wc == (u_short)TIFF_VARIABLE)
            {
                (*getFieldFn)(tif, fip->field_tag, &wc, &cp);
                dir->tdir_count = wc;
            }
            else
                (*getFieldFn)(tif, fip->field_tag, &cp);
            if (!TIFFWriteByteArray(tif, dir, cp))
                return (0);
        }
        break;
    }
    return (1);
}

static void TIFFSetupShortLong(TIFF *tif, ttag_t tag, TIFFDirEntry *dir,
                               uint32_t v)
{
    dir->tdir_tag = tag;
    dir->tdir_count = 1;
    if (v > 0xffffL)
    {
        dir->tdir_type = (short)TIFF_LONG;
        dir->tdir_offset = v;
    }
    else
    {
        dir->tdir_type = (short)TIFF_SHORT;
        dir->tdir_offset = TIFFInsertData(tif, (int)TIFF_SHORT, v);
    }
}

static int TIFFWriteRational(TIFF *tif, TIFFDataType type, ttag_t tag,
                             TIFFDirEntry *dir, float v)
{
    return (TIFFWriteRationalArray(tif, type, tag, dir, 1, &v));
}

static int TIFFWritePerSampleShorts(TIFF *tif, ttag_t tag, TIFFDirEntry *dir)
{
    uint16_t buf[10], v;
    uint16_t *w = buf;
    int i, status, samples = tif->tif_dir.td_samplesperpixel;

    if (samples > NITEMS(buf))
        w = (uint16_t *)_TIFFmalloc(samples * sizeof(uint16_t));
    TIFFGetField(tif, tag, &v);
    for (i = 0; i < samples; i++)
        w[i] = v;
    status = TIFFWriteShortArray(tif, TIFF_SHORT, tag, dir, samples, w);
    if (w != buf)
        _TIFFfree((char *)w);
    return (status);
}

static int TIFFWritePerSampleAnys(TIFF *tif, TIFFDataType type, ttag_t tag,
                                  TIFFDirEntry *dir)
{
    double buf[10], v;
    double *w = buf;
    int i, status;
    int samples = (int)tif->tif_dir.td_samplesperpixel;

    if (samples > NITEMS(buf))
        w = (double *)_TIFFmalloc(samples * sizeof(double));
    TIFFGetField(tif, tag, &v);
    for (i = 0; i < samples; i++)
        w[i] = v;
    status = TIFFWriteAnyArray(tif, type, tag, dir, samples, w);
    if (w != buf)
        _TIFFfree(w);
    return (status);
}

static int TIFFSetupShortPair(TIFF *tif, ttag_t tag, TIFFDirEntry *dir)
{
    uint16_t v[2];

    TIFFGetField(tif, tag, &v[0], &v[1]);
    return (TIFFWriteShortArray(tif, TIFF_SHORT, tag, dir, 2, v));
}

static int TIFFWriteShortTable(TIFF *tif, ttag_t tag, TIFFDirEntry *dir,
                               uint32_t n, uint16_t **table)
{
    uint32_t i, off;

    dir->tdir_tag = tag;
    dir->tdir_type = (short)TIFF_SHORT;
    /* XXX -- yech, fool TIFFWriteData */
    dir->tdir_count = (uint32_t)(1L << tif->tif_dir.td_bitspersample);
    off = tif->tif_dataoff;
    for (i = 0; i < n; i++)
        if (!TIFFWriteData(tif, dir, (char *)table[i]))
            return (0);
    dir->tdir_count *= n;
    dir->tdir_offset = off;
    return (1);
}

static int TIFFWriteByteArray(TIFF *tif, TIFFDirEntry *dir, char *cp)
{
    if (dir->tdir_count > 4)
    {
        if (!TIFFWriteData(tif, dir, cp))
            return (0);
    }
    else
        _TIFFmemcpy(&dir->tdir_offset, cp, dir->tdir_count);
    return (1);
}

static int TIFFWriteShortArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                               TIFFDirEntry *dir, uint32_t n, uint16_t *v)
{
    dir->tdir_tag = tag;
    dir->tdir_type = (short)type;
    dir->tdir_count = n;
    if (n <= 2)
    {
        if (tif->tif_header.tiff_magic == TIFF_BIGENDIAN)
        {
            dir->tdir_offset = (uint32_t)((long)v[0] << 16);
            if (n == 2)
                dir->tdir_offset |= v[1] & 0xffff;
        }
        else
        {
            dir->tdir_offset = v[0] & 0xffff;
            if (n == 2)
                dir->tdir_offset |= (long)v[1] << 16;
        }
        return (1);
    }
    else
        return (TIFFWriteData(tif, dir, (char *)v));
}

static int TIFFWriteLongArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                              TIFFDirEntry *dir, uint32_t n, uint32_t *v)
{
    dir->tdir_tag = tag;
    dir->tdir_type = (short)type;
    dir->tdir_count = n;
    if (n == 1)
    {
        dir->tdir_offset = v[0];
        return (1);
    }
    else
        return (TIFFWriteData(tif, dir, (char *)v));
}

static int TIFFWriteRationalArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                                  TIFFDirEntry *dir, uint32_t n, float *v)
{
    uint32_t i;
    uint32_t *t;
    int status;

    dir->tdir_tag = tag;
    dir->tdir_type = (short)type;
    dir->tdir_count = n;
    t = (uint32_t *)_TIFFmalloc(2 * n * sizeof(uint32_t));
    for (i = 0; i < n; i++)
    {
        float fv = v[i];
        int sign = 1;
        uint32_t den;

        if (fv < 0)
        {
            if (type == TIFF_RATIONAL)
            {
                TIFFWarning(tif->tif_name,
                            "\"%s\": Information lost writing value (%g) as "
                            "(unsigned) RATIONAL",
                            _TIFFFieldWithTag(tif, tag)->field_name, v);
                fv = 0;
            }
            else
                fv = -fv, sign = -1;
        }
        den = 1L;
        if (fv > 0)
        {
            while (fv < 1L << (31 - 3) && den < 1L << (31 - 3))
                fv *= 1 << 3, den *= 1L << 3;
        }
        t[2 * i + 0] = sign * (fv + 0.5);
        t[2 * i + 1] = den;
    }
    status = TIFFWriteData(tif, dir, (char *)t);
    _TIFFfree((char *)t);
    return (status);
}

static int TIFFWriteFloatArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                               TIFFDirEntry *dir, uint32_t n, float *v)
{
    dir->tdir_tag = tag;
    dir->tdir_type = (short)type;
    dir->tdir_count = n;
    TIFFCvtNativeToIEEEFloat(tif, n, v);
    if (n == 1)
    {
        dir->tdir_offset = *(uint32_t *)&v[0];
        return (1);
    }
    else
        return (TIFFWriteData(tif, dir, (char *)v));
}

static int TIFFWriteDoubleArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                                TIFFDirEntry *dir, uint32_t n, double *v)
{
    dir->tdir_tag = tag;
    dir->tdir_type = (short)type;
    dir->tdir_count = n;
    TIFFCvtNativeToIEEEDouble(tif, n, v);
    return (TIFFWriteData(tif, dir, (char *)v));
}

static int TIFFWriteAnyArray(TIFF *tif, TIFFDataType type, ttag_t tag,
                             TIFFDirEntry *dir, uint32_t n, double *v)
{
    char buf[10 * sizeof(double)];
    char *w = buf;
    int i, status = 0;

    if (n * TIFFDataWidth(type) > sizeof buf)
        w = (char *)_TIFFmalloc(n * TIFFDataWidth(type));
    switch (type)
    {
        case TIFF_BYTE:
        {
            unsigned char *bp = (unsigned char *)w;
            for (i = 0; i < n; i++)
                bp[i] = (unsigned char)v[i];
            dir->tdir_tag = tag;
            dir->tdir_type = (short)type;
            dir->tdir_count = n;
            if (!TIFFWriteByteArray(tif, dir, (char *)bp))
                goto out;
        }
        break;
        case TIFF_SBYTE:
        {
            signed char *bp = (signed char *)w;
            for (i = 0; i < n; i++)
                bp[i] = (signed char)v[i];
            dir->tdir_tag = tag;
            dir->tdir_type = (short)type;
            dir->tdir_count = n;
            if (!TIFFWriteByteArray(tif, dir, (char *)bp))
                goto out;
        }
        break;
        case TIFF_SHORT:
        {
            uint16_t *bp = (uint16_t *)w;
            for (i = 0; i < n; i++)
                bp[i] = (uint16_t)v[i];
            if (!TIFFWriteShortArray(tif, type, tag, dir, n, (uint16_t *)bp))
                goto out;
        }
        break;
        case TIFF_SSHORT:
        {
            int16_t *bp = (int16_t *)w;
            for (i = 0; i < n; i++)
                bp[i] = (int16_t)v[i];
            if (!TIFFWriteShortArray(tif, type, tag, dir, n, (uint16_t *)bp))
                goto out;
        }
        break;
        case TIFF_LONG:
        {
            uint32_t *bp = (uint32_t *)w;
            for (i = 0; i < n; i++)
                bp[i] = (uint32_t)v[i];
            if (!TIFFWriteLongArray(tif, type, tag, dir, n, bp))
                goto out;
        }
        break;
        case TIFF_SLONG:
        {
            int32_t *bp = (int32_t *)w;
            for (i = 0; i < n; i++)
                bp[i] = (int32_t)v[i];
            if (!TIFFWriteLongArray(tif, type, tag, dir, n, (uint32_t *)bp))
                goto out;
        }
        break;
        case TIFF_FLOAT:
        {
            float *bp = (float *)w;
            for (i = 0; i < n; i++)
                bp[i] = (float)v[i];
            if (!TIFFWriteFloatArray(tif, type, tag, dir, n, bp))
                goto out;
        }
        break;
        case TIFF_DOUBLE:
            return (TIFFWriteDoubleArray(tif, type, tag, dir, n, v));
        default:
            /* TIFF_NOTYPE */
            /* TIFF_ASCII */
            /* TIFF_UNDEFINED */
            /* TIFF_RATIONAL */
            /* TIFF_SRATIONAL */
            goto out;
    }
    status = 1;
out:
    if (w != buf)
        _TIFFfree(w);
    return (status);
}

static int TIFFWriteTransferFunction(TIFF *tif, TIFFDirEntry *dir)
{
    TIFFDirectory *td = &tif->tif_dir;
    tsize_t n = (1L << td->td_bitspersample) * sizeof(uint16_t);
    uint16_t **tf = td->td_transferfunction;
    int ncols;

    /*
     * Check if the table can be written as a single column,
     * or if it must be written as 3 columns.  Note that we
     * write a 3-column tag if there are 2 samples/pixel and
     * a single column of data won't suffice--hmm.
     */
    switch (td->td_samplesperpixel - td->td_extrasamples)
    {
        default:
            if (_TIFFmemcmp(tf[0], tf[2], n))
            {
                ncols = 3;
                break;
            }
        case 2:
            if (_TIFFmemcmp(tf[0], tf[1], n))
            {
                ncols = 3;
                break;
            }
        case 1:
        case 0:
            ncols = 1;
    }
    return (TIFFWriteShortTable(tif, TIFFTAG_TRANSFERFUNCTION, dir, ncols, tf));
}

static int TIFFWriteData(TIFF *tif, TIFFDirEntry *dir, char *cp)
{
    tsize_t cc;

    if (tif->tif_flags & TIFF_SWAB)
    {
        switch (dir->tdir_type)
        {
            case TIFF_SHORT:
            case TIFF_SSHORT:
                TIFFSwabArrayOfShort((uint16_t *)cp, dir->tdir_count);
                break;
            case TIFF_LONG:
            case TIFF_SLONG:
            case TIFF_FLOAT:
                TIFFSwabArrayOfLong((uint32_t *)cp, dir->tdir_count);
                break;
            case TIFF_RATIONAL:
            case TIFF_SRATIONAL:
                TIFFSwabArrayOfLong((uint32_t *)cp, 2 * dir->tdir_count);
                break;
            case TIFF_DOUBLE:
                TIFFSwabArrayOfDouble((double *)cp, dir->tdir_count);
                break;
        }
    }
    dir->tdir_offset = tif->tif_dataoff;
    cc = dir->tdir_count * TIFFDataWidth(dir->tdir_type);
    if (SeekOK(tif, dir->tdir_offset) && WriteOK(tif, cp, cc))
    {
        tif->tif_dataoff += (cc + 1) & ~1;
        return (1);
    }
    TIFFErrorExtR(tif, tif->tif_name, "Error writing data for field \"%s\"",
                  _TIFFFieldWithTag(tif, dir->tdir_tag)->field_name);
    return (0);
}

static int TIFFLinkDirectory(TIFF *tif)
{
    static const char module[] = "TIFFLinkDirectory";
    uint32_t nextdir;
    uint32_t diroff;

    tif->tif_diroff = (TIFFSeekFile(tif, (toff_t)0, SEEK_END) + 1) & ~1;
    diroff = (uint32_t)tif->tif_diroff;
    if (tif->tif_flags & TIFF_SWAB)
        TIFFSwabLong(&diroff);
#if SUBIFD_SUPPORT
    if (tif->tif_flags & TIFF_INSUBIFD)
    {
        (void)TIFFSeekFile(tif, tif->tif_subifdoff, SEEK_SET);
        if (!WriteOK(tif, &diroff, sizeof(diroff)))
        {
            TIFFErrorExtR(tif, module,
                          "%s: Error writing SubIFD directory link",
                          tif->tif_name);
            return (0);
        }
        /*
         * Advance to the next SubIFD or, if this is
         * the last one configured, revert back to the
         * normal directory linkage.
         */
        if (--tif->tif_nsubifd)
            tif->tif_subifdoff += sizeof(diroff);
        else
            tif->tif_flags &= ~TIFF_INSUBIFD;
        return (1);
    }
#endif
    if (tif->tif_header.tiff_diroff == 0)
    {
        /*
         * First directory, overwrite offset in header.
         */
        tif->tif_header.tiff_diroff = (uint32_t)tif->tif_diroff;
#define HDROFF(f) ((toff_t) & (((TIFFHeader *)0)->f))
        (void)TIFFSeekFile(tif, HDROFF(tiff_diroff), SEEK_SET);
        if (!WriteOK(tif, &diroff, sizeof(diroff)))
        {
            TIFFErrorExtR(tif, tif->tif_name, "Error writing TIFF header");
            return (0);
        }
        return (1);
    }
    /*
     * Not the first directory, search to the last and append.
     */
    nextdir = tif->tif_header.tiff_diroff;
    do
    {
        uint16_t dircount;

        if (!SeekOK(tif, nextdir) || !ReadOK(tif, &dircount, sizeof(dircount)))
        {
            TIFFErrorExtR(tif, module, "Error fetching directory count");
            return (0);
        }
        if (tif->tif_flags & TIFF_SWAB)
            TIFFSwabShort(&dircount);
        (void)TIFFSeekFile(tif, dircount * sizeof(TIFFDirEntry), SEEK_CUR);
        if (!ReadOK(tif, &nextdir, sizeof(nextdir)))
        {
            TIFFErrorExtR(tif, module, "Error fetching directory link");
            return (0);
        }
        if (tif->tif_flags & TIFF_SWAB)
            TIFFSwabLong(&nextdir);
    } while (nextdir != 0);
    (void)TIFFSeekFile(tif, -(toff_t)sizeof(nextdir), SEEK_CUR);
    if (!WriteOK(tif, &diroff, sizeof(diroff)))
    {
        TIFFErrorExtR(tif, module, "Error writing directory link");
        return (0);
    }
    return (1);
}
